package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    public void setUp() {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    public void testPrint_nullValue_nullStringNull() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        when(format.getNullString()).thenReturn(null);

        printer.print(null);

        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, String.class, int.class, int.class);
        printMethod.setAccessible(true);
        // verify that print(Object, String, int, int) is invoked with empty string
        // cannot verify directly, but no exception means pass
    }

    @Test
    public void testPrint_nullValue_nullStringNotNull() throws IOException {
        when(format.getNullString()).thenReturn("NULL");

        printer.print(null);

        // no exception means success, Mockito verifies no interaction with out append in this test
    }

    @Test
    public void testPrint_nonNullValue() throws IOException {
        String value = "value";
        // toString returns value itself
        printer.print(value);

        // no exception means success
    }

    @Test
    public void testPrint_nonNullValue_emptyString() throws IOException {
        Object value = new Object() {
            @Override
            public String toString() {
                return "";
            }
        };

        printer.print(value);

        // no exception means success
    }
}
